            <div className="products-grid">
              {sample.map((p, i) => (
                <article className="product-card" key={i}>
                  <div className="product-media">
                    <img src={p.image} alt={p.name} />
                  </div>
                  <p className="category">{p.category}</p>
                  <h3>{p.name}</h3>
                  <p className="price">${p.price}</p>
                </article>
              ))}
            </div>
          );
        })()}
      </section>
    </div>
  );
}

export default Home;
